class Solution {
    public int maxScore(String s) {
        int maxScore = 0;
        int leftZeros = 0;
        for (int i = 0; i < s.length() - 1; i++) {
            if (s.charAt(i) == '0') {
                leftZeros++;
            }
            int rightOnes = 0;
            for (int j = i + 1; j < s.length(); j++) {
                if (s.charAt(j) == '1') {
                    rightOnes++;
                }
                maxScore = Math.max(maxScore, leftZeros + rightOnes);
            }
        }
        return maxScore;
    }
}
